beforeSaveCustomScript:
$clockIn  = entity\attribute('firstClockIn');
$clockOut = entity\attribute('lastClockOut');
$date     = entity\attribute('date');
$user     = entity\attribute('assignedUserId');

// ✅ Sync userId
entity\setAttribute('userId', $user);

// ✅ Weekend validation
if ($date) {
    $day = datetime\dayOfWeek($date);

    if ($day == 0 || $day == 6) {
        recordService\throwBadRequest(
            "Attendance can't be created on Saturday or Sunday"
        );
    }
}

// ✅ Validate Clock In only if exists
if ($clockIn) {

    // 🔹 Extract time part
    $clockInTime = datetime\format(
        $clockIn,
        null,
        'HH:mm:ss'
    );

    // 🔹 Validate Clock In time
    if ($clockInTime < '08:30:00') {
        recordService\throwBadRequest(
            "Clock In time cannot be earlier than 08:30 AM"
        );
    }
}

// ✅ If Clock Out is missing → set default values
if (!$clockOut) {
    entity\setAttribute('totalWorkSeconds', 0);
    entity\setAttribute('totalHours', '00:00:00');
}

// ✅ If both Clock In and Clock Out exist → calculate
if ($clockIn && $clockOut) {

    // 🔹 Calculate difference
    $diff = datetime\diff($clockOut, $clockIn, 'seconds');

    if ($diff <= 0) {
        recordService\throwBadRequest(
            "Clock Out must be greater than Clock In"
        );
    }

    // ✅ Store seconds
    entity\setAttribute('totalWorkSeconds', $diff);

    // 🔹 Convert seconds → HH:mm:ss
    $hours   = ($diff - ($diff % 3600)) / 3600;
    $minutes = (($diff % 3600) - ($diff % 60)) / 60;
    $seconds = $diff % 60;

    // 🔹 Padding
    $hh = ifThenElse(
        $hours < 10,
        string\concatenate('0', $hours),
        $hours
    );

    $mm = ifThenElse(
        $minutes < 10,
        string\concatenate('0', $minutes),
        $minutes
    );

    $ss = ifThenElse(
        $seconds < 10,
        string\concatenate('0', $seconds),
        $seconds
    );

    $formattedTime = string\concatenate(
        string\concatenate($hh, ':'),
        string\concatenate(
            $mm,
            string\concatenate(':', $ss)
        )
    );

    // ✅ Store formatted time
    entity\setAttribute('totalHours', $formattedTime);
}

